// Generated by OrchestKit Claude Plugin
// Created: 2026-04-17

/**
 * Metrics Bridge — PostToolUse hook (all matchers)
 *
 * Usage-Driven Hardening milestone close-out. Accumulates per-session
 * metrics into `.claude/state/ork-metrics-{session_id}.json` so analytics
 * pipelines can `jq` across sessions without parsing jsonl event streams.
 *
 * What we count (per session):
 *   - `edits`        Write/Edit/MultiEdit tool calls
 *   - `test_runs`    Bash commands matching test-runner patterns
 *   - `commits`      Bash commands starting with `git commit`
 *   - `bash_calls`   all Bash invocations
 *   - `agent_spawns` Agent tool calls
 *   - `started_at`   ISO timestamp of first event seen this session
 *   - `updated_at`   ISO timestamp of most recent event
 *
 * File format is a flat JSON object (not JSONL) so readers don't need
 * line-at-a-time parsing. Writes use atomicWriteSync so concurrent hooks
 * never see a torn file. Cap at 1MB (shouldn't happen in practice but
 * bounds runaway scenarios).
 */

import { existsSync, readFileSync, mkdirSync, statSync } from 'node:fs';
import { dirname, join } from 'node:path';
import type { HookInput, HookResult, HookContext } from '../types.js';
import { outputSilentSuccess, getField, getSessionId } from '../lib/common.js';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { sanitizeSessionId } from '../lib/sanitize-shell.js';
import { NOOP_CTX } from '../lib/context.js';

const HOOK_NAME = 'posttool/metrics-bridge';
const MAX_BYTES = 1_000_000;

const TEST_COMMAND_RE =
  /(^|[&;|\s])(npm\s+(run\s+)?test\b|vitest\b|jest\b|pytest\b|bun\s+test\b|deno\s+test\b|cargo\s+test\b|go\s+test\b|rspec\b|phpunit\b)/;
const GIT_COMMIT_RE = /(^|[&;|\s])git\s+commit\b/;

interface SessionMetrics {
  session_id: string;
  started_at: string;
  updated_at: string;
  edits: number;
  test_runs: number;
  commits: number;
  bash_calls: number;
  agent_spawns: number;
}

export function getMetricsPath(projectDir: string, sessionId: string): string {
  const safe = sanitizeSessionId(sessionId) || 'unknown';
  return join(projectDir, '.claude', 'state', `ork-metrics-${safe}.json`);
}

function emptyMetrics(sessionId: string): SessionMetrics {
  const iso = new Date().toISOString();
  return {
    session_id: sessionId,
    started_at: iso,
    updated_at: iso,
    edits: 0,
    test_runs: 0,
    commits: 0,
    bash_calls: 0,
    agent_spawns: 0,
  };
}

function loadMetrics(path: string, sessionId: string): SessionMetrics {
  if (!existsSync(path)) return emptyMetrics(sessionId);
  try {
    const s = statSync(path);
    if (s.size > MAX_BYTES) return emptyMetrics(sessionId);
    const parsed = JSON.parse(readFileSync(path, 'utf8')) as SessionMetrics;
    // Ensure all keys exist even if an older schema wrote here.
    return { ...emptyMetrics(sessionId), ...parsed, session_id: sessionId };
  } catch {
    return emptyMetrics(sessionId);
  }
}

function saveMetrics(path: string, metrics: SessionMetrics): void {
  try {
    mkdirSync(dirname(path), { recursive: true });
    atomicWriteSync(path, JSON.stringify(metrics, null, 2), 'utf8');
  } catch {
    // Best-effort. Analytics is not a correctness requirement.
  }
}

/**
 * Apply the increment described by this tool call to the metrics object
 * in-place. Returns true if anything changed (so we can skip the write
 * when the event is uninteresting).
 */
function applyEvent(
  metrics: SessionMetrics,
  toolName: string,
  command: string,
): boolean {
  let changed = false;

  if (toolName === 'Write' || toolName === 'Edit' || toolName === 'MultiEdit') {
    metrics.edits += 1;
    changed = true;
  } else if (toolName === 'Bash') {
    metrics.bash_calls += 1;
    changed = true;
    if (TEST_COMMAND_RE.test(command)) metrics.test_runs += 1;
    if (GIT_COMMIT_RE.test(command)) metrics.commits += 1;
  } else if (toolName === 'Agent' || toolName === 'Task') {
    metrics.agent_spawns += 1;
    changed = true;
  }

  if (changed) metrics.updated_at = new Date().toISOString();
  return changed;
}

export function metricsBridge(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const toolName = input.tool_name || '';
  if (!toolName) return outputSilentSuccess();

  const sessionId = input.session_id || getSessionId();
  if (!sessionId) return outputSilentSuccess();

  const command = getField<string>(input, 'tool_input.command') || '';
  const path = getMetricsPath(ctx.projectDir, sessionId);

  const metrics = loadMetrics(path, sessionId);
  const changed = applyEvent(metrics, toolName, command);
  if (!changed) return outputSilentSuccess();

  saveMetrics(path, metrics);
  ctx.log(HOOK_NAME, `${toolName} → ${JSON.stringify(metrics).slice(0, 120)}…`);

  return outputSilentSuccess();
}

// Testing exports
export {
  TEST_COMMAND_RE,
  GIT_COMMIT_RE,
  emptyMetrics,
  loadMetrics,
  saveMetrics,
  applyEvent,
};
